import InputForm from "../Components/Input/InputForm";

function IdentificationPage() {
  return (
    <div style={{
    display:"flex",
    flexDirection: "column",
    position: "absolute", 
    right: "0", 
    top: "50%", 
    transform: "translateY(-50%)",
    maxWidth: "720px",
    maxHeight: "745px",
    padding: "20px",
    justifyContent:"center",
    width: "100%",
    height: "100%"
    
    }}>
    <p>Выполните вход чтобы продолжить</p>
    <InputForm TextPlaceholder="Register"/>
    </div>
  );
}

export default IdentificationPage;
